// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const legalCcProfessionalQuestions: Question[] = [
  { id: 'legal-cc-prof-1', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-professional', competencyId: 'legal-corporate-compliance', type: 'multiple-choice', content: { es: 'Durante una auditoría interna, se descubre que una división de la empresa ha estado operando sin cumplir una regulación sectorial clave durante 18 meses. No hay daños conocidos aún. ¿Qué acción toma primero?', en: 'During an internal audit, it is discovered that a company division has been operating without complying with a key sector regulation for 18 months. No known damages yet. What action do you take first?', fr: 'Lors d\'un audit interne, on découvre qu\'une division de l\'entreprise opère sans respecter une réglementation sectorielle clé depuis 18 mois. Aucun dommage connu encore. Quelle action prenez-vous en premier ?' }, options: [{ id: 'a', text: { es: 'Corregir silenciosamente el incumplimiento y esperar que nadie lo note', en: 'Quietly correct the non-compliance and hope no one notices', fr: 'Corriger silencieusement la non-conformité et espérer que personne ne le remarque' }, value: 0 }, { id: 'b', text: { es: 'Documentar la situación, evaluar la exposición legal, implementar un plan de remediación inmediato, considerar la autodivulgación al regulador según la jurisdicción, y reforzar los controles internos para prevenir recurrencia', en: 'Document the situation, assess legal exposure, implement an immediate remediation plan, consider self-disclosure to the regulator per jurisdiction, and strengthen internal controls to prevent recurrence', fr: 'Documenter la situation, évaluer l\'exposition juridique, mettre en œuvre un plan de remédiation immédiat, envisager l\'autodéclaration au régulateur selon la juridiction, et renforcer les contrôles internes pour prévenir la récurrence' }, value: 100 }, { id: 'c', text: { es: 'Informar solo a la alta dirección y dejar que ellos decidan', en: 'Inform only senior management and let them decide', fr: 'Informer uniquement la direction et les laisser décider' }, value: 25 }, { id: 'd', text: { es: 'Contratar un bufete externo para manejar la situación', en: 'Hire an external law firm to handle the situation', fr: 'Engager un cabinet externe pour gérer la situation' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'legal-cc-prof-2', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-professional', competencyId: 'legal-contract-management', type: 'multiple-choice', content: { es: 'La empresa gestiona más de 500 contratos activos con proveedores, pero no existe un sistema centralizado de seguimiento. Se han perdido plazos de renovación y condiciones favorables. ¿Qué solución implementa?', en: 'The company manages over 500 active vendor contracts, but there is no centralized tracking system. Renewal deadlines and favorable terms have been missed. What solution do you implement?', fr: 'L\'entreprise gère plus de 500 contrats actifs avec des fournisseurs, mais il n\'y a pas de système centralisé de suivi. Des délais de renouvellement et des conditions favorables ont été manqués. Quelle solution mettez-vous en place ?' }, options: [{ id: 'a', text: { es: 'Crear una hoja de cálculo compartida con los datos de cada contrato', en: 'Create a shared spreadsheet with each contract\'s data', fr: 'Créer une feuille de calcul partagée avec les données de chaque contrat' }, value: 25 }, { id: 'b', text: { es: 'Implementar un sistema de gestión de contratos (CLM) con alertas automáticas de vencimiento, cláusulas estándar aprobadas, flujos de aprobación digital, y dashboards de rendimiento por proveedor', en: 'Implement a contract lifecycle management (CLM) system with automatic expiration alerts, approved standard clauses, digital approval workflows, and per-vendor performance dashboards', fr: 'Implémenter un système de gestion du cycle de vie des contrats (CLM) avec des alertes automatiques d\'expiration, des clauses standard approuvées, des flux d\'approbation numériques, et des tableaux de bord de performance par fournisseur' }, value: 100 }, { id: 'c', text: { es: 'Asignar un paralegal dedicado al seguimiento de contratos', en: 'Assign a dedicated paralegal to contract tracking', fr: 'Assigner un parajuriste dédié au suivi des contrats' }, value: 25 }, { id: 'd', text: { es: 'Pedir a cada departamento que gestione sus propios contratos', en: 'Ask each department to manage their own contracts', fr: 'Demander à chaque département de gérer ses propres contrats' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'legal-cc-prof-3', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-professional', competencyId: 'legal-risk-assessment', type: 'multiple-choice', content: { es: 'El CEO quiere lanzar un nuevo producto al mercado en 3 meses. Su evaluación legal identifica riesgos regulatorios significativos que podrían retrasar el lanzamiento 6 meses más. ¿Cómo presenta su análisis?', en: 'The CEO wants to launch a new product in 3 months. Your legal assessment identifies significant regulatory risks that could delay launch by 6 more months. How do you present your analysis?', fr: 'Le PDG veut lancer un nouveau produit dans 3 mois. Votre évaluation juridique identifie des risques réglementaires significatifs pouvant retarder le lancement de 6 mois. Comment présentez-vous votre analyse ?' }, options: [{ id: 'a', text: { es: 'Informar que el lanzamiento no es posible en el plazo previsto', en: 'Report that the launch is not possible in the planned timeframe', fr: 'Informer que le lancement n\'est pas possible dans le délai prévu' }, value: 0 }, { id: 'b', text: { es: 'Presentar un análisis de riesgos cuantificado con tres escenarios (conservador, moderado, agresivo), cada uno con probabilidades, impacto financiero, medidas de mitigación específicas, y un plan acelerado que mantenga la gestión de riesgos', en: 'Present a quantified risk analysis with three scenarios (conservative, moderate, aggressive), each with probabilities, financial impact, specific mitigation measures, and an accelerated plan maintaining risk management', fr: 'Présenter une analyse de risques quantifiée avec trois scénarios (conservateur, modéré, agressif), chacun avec des probabilités, un impact financier, des mesures d\'atténuation spécifiques, et un plan accéléré maintenant la gestion des risques' }, value: 100 }, { id: 'c', text: { es: 'Aprobar el lanzamiento asumiendo que los riesgos son manejables', en: 'Approve the launch assuming risks are manageable', fr: 'Approuver le lancement en supposant que les risques sont gérables' }, value: 0 }, { id: 'd', text: { es: 'Solicitar una opinión legal externa antes de opinar', en: 'Request an external legal opinion before commenting', fr: 'Demander un avis juridique externe avant de se prononcer' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'legal-cc-prof-4', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-professional', competencyId: 'legal-regulatory-affairs', type: 'scale', content: { es: '¿Cómo califica su conocimiento de los marcos regulatorios aplicables al sector de su empresa y su capacidad para gestionar relaciones con autoridades regulatorias?', en: 'How do you rate your knowledge of regulatory frameworks applicable to your company\'s sector and your ability to manage relationships with regulatory authorities?', fr: 'Comment évaluez-vous votre connaissance des cadres réglementaires applicables au secteur de votre entreprise et votre capacité à gérer les relations avec les autorités réglementaires ?' }, scaleMin: 1, scaleMax: 5, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'legal-cc-prof-5', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-professional', competencyId: 'legal-corporate-compliance', type: 'scenario', content: { es: 'Un whistleblower interno reporta que el director comercial ha estado ofreciendo pagos indebidos a funcionarios gubernamentales para obtener contratos en un mercado internacional clave. El director comercial genera el 25% de los ingresos de la empresa. El CEO le pide que "investigue discretamente".\n\nDescriba cómo manejaría esta situación desde la perspectiva legal corporativa.', en: 'An internal whistleblower reports the commercial director has been making improper payments to government officials to obtain contracts in a key international market. The commercial director generates 25% of company revenue. The CEO asks you to "investigate discreetly."\n\nDescribe how you would handle this from a corporate legal perspective.', fr: 'Un lanceur d\'alerte interne signale que le directeur commercial a offert des paiements indus à des fonctionnaires gouvernementaux pour obtenir des contrats sur un marché international clé. Le directeur commercial génère 25% des revenus. Le PDG vous demande d\'enquêter discrètement.\n\nDécrivez comment vous géreriez cette situation depuis la perspective juridique d\'entreprise.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'legal-cc-prof-6', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-professional', competencyId: 'legal-contract-management', type: 'open-text', content: { es: 'Describa cómo optimizaría el proceso de gestión de contratos en una empresa con cientos de acuerdos activos. ¿Qué tecnologías, procesos y métricas implementaría?', en: 'Describe how you would optimize the contract management process in a company with hundreds of active agreements. What technologies, processes, and metrics would you implement?', fr: 'Décrivez comment vous optimiseriez le processus de gestion des contrats dans une entreprise avec des centaines d\'accords actifs. Quelles technologies, processus et métriques mettriez-vous en place ?' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const legalCcSoftSkillsQuestions: Question[] = [
  { id: 'legal-cc-ss-1', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-soft-skills', competencyId: 'legal-business-acumen', type: 'multiple-choice', content: { es: 'El área de ventas quiere cerrar un acuerdo importante con un cliente que exige términos contractuales que usted considera riesgosos. El VP de ventas argumenta que "el departamento legal siempre bloquea negocios". ¿Cómo maneja la situación?', en: 'The sales team wants to close an important deal with a client demanding contract terms you consider risky. The VP of sales argues that "the legal department always blocks deals." How do you handle it?', fr: 'L\'équipe commerciale veut conclure un accord important avec un client exigeant des termes contractuels que vous considérez risqués. Le VP des ventes argue que "le département juridique bloque toujours les affaires." Comment gérez-vous ?' }, options: [{ id: 'a', text: { es: 'Bloquear el acuerdo hasta que se cumplan todos sus requisitos legales', en: 'Block the deal until all your legal requirements are met', fr: 'Bloquer l\'accord jusqu\'à ce que toutes vos exigences juridiques soient satisfaites' }, value: 0 }, { id: 'b', text: { es: 'Reunirse con ventas para entender los objetivos comerciales, cuantificar los riesgos en términos de impacto financiero, proponer alternativas contractuales que protejan a la empresa sin perder el negocio, y presentar opciones con análisis costo-beneficio', en: 'Meet with sales to understand business objectives, quantify risks in financial impact terms, propose contract alternatives that protect the company without losing the deal, and present options with cost-benefit analysis', fr: 'Rencontrer les ventes pour comprendre les objectifs, quantifier les risques en termes d\'impact financier, proposer des alternatives contractuelles protégeant l\'entreprise sans perdre l\'affaire, et présenter des options avec analyse coûts-bénéfices' }, value: 100 }, { id: 'c', text: { es: 'Aprobar el acuerdo para no obstaculizar el negocio', en: 'Approve the deal to not obstruct business', fr: 'Approuver l\'accord pour ne pas entraver les affaires' }, value: 0 }, { id: 'd', text: { es: 'Escalar directamente al CEO', en: 'Escalate directly to the CEO', fr: 'Escalader directement au PDG' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'legal-cc-ss-2', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-soft-skills', competencyId: 'legal-stakeholder-management', type: 'multiple-choice', content: { es: 'La junta directiva solicita una presentación sobre la exposición legal de la empresa. Tiene 15 minutos para cubrir 8 temas complejos. ¿Cómo prepara su presentación?', en: 'The board of directors requests a presentation on the company\'s legal exposure. You have 15 minutes to cover 8 complex topics. How do you prepare?', fr: 'Le conseil d\'administration demande une présentation sur l\'exposition juridique de l\'entreprise. Vous avez 15 minutes pour couvrir 8 sujets complexes. Comment préparez-vous ?' }, options: [{ id: 'a', text: { es: 'Preparar un documento detallado de 30 páginas con todo el análisis', en: 'Prepare a detailed 30-page document with the full analysis', fr: 'Préparer un document détaillé de 30 pages avec toute l\'analyse' }, value: 0 }, { id: 'b', text: { es: 'Crear un resumen ejecutivo visual con un mapa de calor de riesgos, cifras clave de exposición financiera, las 3 prioridades urgentes con acciones recomendadas, y un apéndice detallado disponible para quien quiera profundizar', en: 'Create a visual executive summary with a risk heat map, key financial exposure figures, top 3 urgent priorities with recommended actions, and a detailed appendix available for those wanting to dive deeper', fr: 'Créer un résumé exécutif visuel avec une carte de chaleur des risques, les chiffres clés d\'exposition financière, les 3 priorités urgentes avec actions recommandées, et une annexe détaillée disponible pour approfondir' }, value: 100 }, { id: 'c', text: { es: 'Cubrir solo los 3 temas más importantes en detalle', en: 'Cover only the 3 most important topics in detail', fr: 'Ne couvrir que les 3 sujets les plus importants en détail' }, value: 25 }, { id: 'd', text: { es: 'Solicitar más tiempo para la presentación', en: 'Request more time for the presentation', fr: 'Demander plus de temps pour la présentation' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'legal-cc-ss-3', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-soft-skills', competencyId: 'legal-negotiation-influence', type: 'multiple-choice', content: { es: 'Está negociando una adquisición importante. La contraparte presenta una posición muy agresiva en las representaciones y garantías, exigiendo que la empresa asuma responsabilidad ilimitada. ¿Cómo negocia?', en: 'You are negotiating an important acquisition. The counterpart presents a very aggressive position on representations and warranties, demanding the company assume unlimited liability. How do you negotiate?', fr: 'Vous négociez une acquisition importante. La partie adverse présente une position très agressive sur les déclarations et garanties, exigeant que l\'entreprise assume une responsabilité illimitée. Comment négociez-vous ?' }, options: [{ id: 'a', text: { es: 'Rechazar completamente y mantener su posición', en: 'Completely reject and hold your position', fr: 'Rejeter complètement et maintenir votre position' }, value: 0 }, { id: 'b', text: { es: 'Analizar cada representación individualmente, proponer caps de responsabilidad proporcionales al riesgo, establecer baskets y deductibles razonables, limitar la duración de las garantías, y negociar un mecanismo de indemnización equilibrado', en: 'Analyze each representation individually, propose liability caps proportional to risk, establish reasonable baskets and deductibles, limit warranty duration, and negotiate a balanced indemnification mechanism', fr: 'Analyser chaque déclaration individuellement, proposer des plafonds de responsabilité proportionnels au risque, établir des seuils et franchises raisonnables, limiter la durée des garanties, et négocier un mécanisme d\'indemnisation équilibré' }, value: 100 }, { id: 'c', text: { es: 'Aceptar para no poner en riesgo la transacción', en: 'Accept to not jeopardize the transaction', fr: 'Accepter pour ne pas mettre en péril la transaction' }, value: 0 }, { id: 'd', text: { es: 'Proponer un seguro de representaciones y garantías como solución única', en: 'Propose a representations and warranties insurance as the sole solution', fr: 'Proposer une assurance de déclarations et garanties comme solution unique' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'legal-cc-ss-4', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-soft-skills', competencyId: 'legal-business-acumen', type: 'scale', content: { es: '¿Cómo califica su capacidad para comprender los objetivos de negocio y traducir riesgos legales en términos que las áreas comerciales puedan entender y actuar?', en: 'How do you rate your ability to understand business objectives and translate legal risks into terms that commercial areas can understand and act upon?', fr: 'Comment évaluez-vous votre capacité à comprendre les objectifs commerciaux et traduire les risques juridiques en termes compréhensibles et actionnables par les équipes commerciales ?' }, scaleMin: 1, scaleMax: 5, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'legal-cc-ss-5', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-soft-skills', competencyId: 'legal-stakeholder-management', type: 'scenario', content: { es: 'La empresa está considerando una fusión transformacional. El CEO es entusiasta, el CFO está preocupado por la deuda, el COO teme la integración operativa, y dos miembros de la junta tienen conflictos de interés no declarados. Usted debe asesorar legalmente garantizando que todos los stakeholders estén alineados y protegidos.\n\nDescriba su estrategia para gestionar esta situación compleja con múltiples stakeholders.', en: 'The company is considering a transformational merger. The CEO is enthusiastic, the CFO is concerned about debt, the COO fears operational integration, and two board members have undeclared conflicts of interest. You must provide legal advice ensuring all stakeholders are aligned and protected.\n\nDescribe your strategy for managing this complex multi-stakeholder situation.', fr: 'L\'entreprise envisage une fusion transformationnelle. Le PDG est enthousiaste, le DAF s\'inquiète de la dette, le DG craint l\'intégration opérationnelle, et deux membres du conseil ont des conflits d\'intérêts non déclarés. Vous devez conseiller juridiquement en alignant tous les stakeholders.\n\nDécrivez votre stratégie pour gérer cette situation complexe.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'legal-cc-ss-6', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-soft-skills', competencyId: 'legal-negotiation-influence', type: 'open-text', content: { es: 'Describa su enfoque para negociar acuerdos comerciales complejos donde debe equilibrar la protección legal de la empresa con la necesidad de cerrar el negocio. ¿Cómo determina cuáles son los puntos negociables y los innegociables?', en: 'Describe your approach to negotiating complex commercial agreements where you must balance corporate legal protection with the need to close the deal. How do you determine negotiable vs. non-negotiable points?', fr: 'Décrivez votre approche pour négocier des accords commerciaux complexes où vous devez équilibrer la protection juridique de l\'entreprise avec la nécessité de conclure l\'affaire. Comment déterminez-vous les points négociables et non négociables ?' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const legalCcReadinessQuestions: Question[] = [
  { id: 'legal-cc-rd-1', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-readiness', competencyId: 'legal-data-privacy', type: 'multiple-choice', content: { es: 'La empresa lanza un nuevo producto digital que recopila datos biométricos de usuarios en 5 países con regulaciones de privacidad diferentes. El equipo de producto no ha considerado las implicaciones legales. ¿Cómo interviene?', en: 'The company launches a new digital product collecting biometric data from users in 5 countries with different privacy regulations. The product team has not considered legal implications. How do you intervene?', fr: 'L\'entreprise lance un nouveau produit numérique collectant des données biométriques d\'utilisateurs dans 5 pays avec des réglementations différentes. L\'équipe produit n\'a pas considéré les implications juridiques. Comment intervenez-vous ?' }, options: [{ id: 'a', text: { es: 'Detener el lanzamiento hasta completar un análisis legal completo', en: 'Stop the launch until a complete legal analysis is done', fr: 'Arrêter le lancement jusqu\'à ce qu\'une analyse juridique complète soit faite' }, value: 25 }, { id: 'b', text: { es: 'Realizar una evaluación de impacto de privacidad (DPIA), mapear los requisitos legales por jurisdicción, diseñar un marco de cumplimiento escalable, implementar privacy by design en el producto, y establecer un proceso continuo de monitoreo regulatorio', en: 'Conduct a data protection impact assessment (DPIA), map legal requirements by jurisdiction, design a scalable compliance framework, implement privacy by design in the product, and establish ongoing regulatory monitoring', fr: 'Réaliser une évaluation d\'impact sur la protection des données (AIPD), cartographier les exigences légales par juridiction, concevoir un cadre de conformité évolutif, implémenter le privacy by design dans le produit, et établir un suivi réglementaire continu' }, value: 100 }, { id: 'c', text: { es: 'Aprobar el lanzamiento con un aviso de privacidad genérico', en: 'Approve the launch with a generic privacy notice', fr: 'Approuver le lancement avec un avis de confidentialité générique' }, value: 0 }, { id: 'd', text: { es: 'Contratar un bufete especializado en privacidad de datos', en: 'Hire a law firm specializing in data privacy', fr: 'Engager un cabinet spécialisé en protection des données' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'legal-cc-rd-2', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-readiness', competencyId: 'legal-esg-sustainability', type: 'multiple-choice', content: { es: 'La nueva regulación de la UE sobre reportes de sostenibilidad corporativa (CSRD) aplica a su empresa. La dirección lo ve como un "requisito más de compliance". ¿Cómo posiciona la iniciativa?', en: 'The new EU Corporate Sustainability Reporting Directive (CSRD) applies to your company. Management sees it as "just another compliance requirement." How do you position the initiative?', fr: 'La nouvelle directive européenne sur les rapports de durabilité (CSRD) s\'applique à votre entreprise. La direction la voit comme "une exigence de conformité de plus." Comment positionnez-vous l\'initiative ?' }, options: [{ id: 'a', text: { es: 'Tratar la CSRD como un ejercicio de compliance estándar', en: 'Treat CSRD as a standard compliance exercise', fr: 'Traiter la CSRD comme un exercice de conformité standard' }, value: 25 }, { id: 'b', text: { es: 'Demostrar el valor estratégico: ventaja competitiva con inversores ESG, reducción de riesgos legales, mejora de reputación corporativa, acceso a financiamiento verde, y alineamiento con expectativas de clientes y talento', en: 'Demonstrate strategic value: competitive advantage with ESG investors, legal risk reduction, corporate reputation improvement, access to green financing, and alignment with client and talent expectations', fr: 'Démontrer la valeur stratégique : avantage concurrentiel avec les investisseurs ESG, réduction des risques juridiques, amélioration de la réputation, accès au financement vert, et alignement avec les attentes des clients et talents' }, value: 100 }, { id: 'c', text: { es: 'Contratar consultores ESG para manejar todo el proceso', en: 'Hire ESG consultants to handle the entire process', fr: 'Engager des consultants ESG pour gérer tout le processus' }, value: 0 }, { id: 'd', text: { es: 'Esperar a ver cómo otras empresas del sector implementan la regulación', en: 'Wait to see how other companies in the sector implement the regulation', fr: 'Attendre de voir comment d\'autres entreprises du secteur implémentent la réglementation' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'legal-cc-rd-3', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-readiness', competencyId: 'legal-operations-automation', type: 'multiple-choice', content: { es: 'El departamento legal procesa manualmente 200 NDAs al mes, lo que consume el 40% del tiempo del equipo. ¿Cómo automatiza el proceso?', en: 'The legal department manually processes 200 NDAs per month, consuming 40% of the team\'s time. How do you automate the process?', fr: 'Le département juridique traite manuellement 200 accords de confidentialité par mois, consommant 40% du temps de l\'équipe. Comment automatisez-vous le processus ?' }, options: [{ id: 'a', text: { es: 'Crear templates en Word y delegar el proceso a asistentes', en: 'Create Word templates and delegate the process to assistants', fr: 'Créer des modèles Word et déléguer le processus aux assistants' }, value: 25 }, { id: 'b', text: { es: 'Implementar una plataforma de auto-servicio con templates inteligentes, cláusulas pre-aprobadas según nivel de riesgo, flujos de aprobación automatizados, firma electrónica integrada, y escalamiento automático solo para términos no estándar', en: 'Implement a self-service platform with smart templates, pre-approved clauses by risk level, automated approval workflows, integrated e-signature, and automatic escalation only for non-standard terms', fr: 'Implémenter une plateforme en libre-service avec des modèles intelligents, des clauses pré-approuvées par niveau de risque, des flux d\'approbation automatisés, signature électronique intégrée, et escalade automatique uniquement pour les termes non standard' }, value: 100 }, { id: 'c', text: { es: 'Contratar más personal para procesar los NDAs', en: 'Hire more staff to process the NDAs', fr: 'Recruter plus de personnel pour traiter les accords' }, value: 0 }, { id: 'd', text: { es: 'Eliminar el requisito de NDA para transacciones menores', en: 'Eliminate the NDA requirement for minor transactions', fr: 'Éliminer l\'exigence d\'accord de confidentialité pour les transactions mineures' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'legal-cc-rd-4', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-readiness', competencyId: 'legal-data-privacy', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene en regulaciones de privacidad de datos (GDPR, LGPD, CCPA) y ciberseguridad aplicadas al entorno corporativo?', en: 'What level of experience do you have with data privacy regulations (GDPR, LGPD, CCPA) and cybersecurity applied to the corporate environment?', fr: 'Quel niveau d\'expérience avez-vous avec les réglementations de protection des données (RGPD, LGPD, CCPA) et la cybersécurité appliquées à l\'environnement d\'entreprise ?' }, scaleMin: 1, scaleMax: 5, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'legal-cc-rd-5', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-readiness', competencyId: 'legal-esg-sustainability', type: 'scenario', content: { es: 'Su empresa opera en un sector con alto impacto ambiental. Un grupo de inversores institucionales exige un plan de transición climática creíble antes de renovar su participación. La empresa no tiene un abogado especializado en ESG, y las regulaciones de sostenibilidad evolucionan rápidamente en las 3 jurisdicciones donde opera.\n\nDescriba cómo lideraría desde el departamento legal la respuesta a esta exigencia de los inversores.', en: 'Your company operates in a high environmental impact sector. Institutional investors demand a credible climate transition plan before renewing their stake. The company has no ESG-specialized attorney, and sustainability regulations evolve rapidly across the 3 jurisdictions where it operates.\n\nDescribe how you would lead the legal department\'s response to this investor demand.', fr: 'Votre entreprise opère dans un secteur à fort impact environnemental. Des investisseurs institutionnels exigent un plan de transition climatique crédible avant de renouveler leur participation. L\'entreprise n\'a pas d\'avocat spécialisé en ESG, et les réglementations évoluent rapidement dans les 3 juridictions d\'opération.\n\nDécrivez comment vous meneriez la réponse du département juridique.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'legal-cc-rd-6', profileId: 'legal-corporate-counsel', categoryId: 'legal-cc-readiness', competencyId: 'legal-operations-automation', type: 'open-text', content: { es: 'Describa su visión para transformar las operaciones del departamento legal utilizando automatización e inteligencia artificial. ¿Qué procesos priorizaría y cómo gestionaría el cambio con el equipo?', en: 'Describe your vision for transforming legal department operations using automation and AI. What processes would you prioritize and how would you manage the change with the team?', fr: 'Décrivez votre vision pour transformer les opérations du département juridique en utilisant l\'automatisation et l\'IA. Quels processus prioriseriez-vous et comment géreriez-vous le changement avec l\'équipe ?' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

