// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const legalPlProfessionalQuestions: Question[] = [
  { id: 'legal-pl-prof-1', profileId: 'legal-paralegal', categoryId: 'legal-pl-professional', competencyId: 'legal-research-preparation', type: 'multiple-choice', content: { es: 'El abogado a cargo le pide preparar un resumen de jurisprudencia relevante para un caso de responsabilidad civil con audiencia en 5 días. La base de datos tiene más de 200 sentencias potencialmente relevantes. ¿Cómo organiza su investigación?', en: 'The lead attorney asks you to prepare a summary of relevant case law for a civil liability case with a hearing in 5 days. The database has over 200 potentially relevant rulings. How do you organize your research?', fr: 'L\'avocat en charge vous demande de préparer un résumé de jurisprudence pertinente pour un dossier de responsabilité civile avec audience dans 5 jours. La base de données contient plus de 200 décisions potentiellement pertinentes. Comment organisez-vous votre recherche ?' }, options: [{ id: 'a', text: { es: 'Leer todas las 200 sentencias cronológicamente', en: 'Read all 200 rulings chronologically', fr: 'Lire les 200 décisions chronologiquement' }, value: 0 }, { id: 'b', text: { es: 'Definir criterios de búsqueda específicos, filtrar por relevancia y jurisdicción, categorizar por tema legal, crear un memo estructurado con las sentencias más relevantes y sus implicaciones para el caso', en: 'Define specific search criteria, filter by relevance and jurisdiction, categorize by legal topic, create a structured memo with the most relevant rulings and their implications for the case', fr: 'Définir des critères de recherche spécifiques, filtrer par pertinence et juridiction, catégoriser par sujet juridique, créer un mémo structuré avec les décisions les plus pertinentes et leurs implications' }, value: 100 }, { id: 'c', text: { es: 'Pedir al abogado que especifique qué sentencias quiere', en: 'Ask the attorney to specify which rulings they want', fr: 'Demander à l\'avocat de préciser quelles décisions il veut' }, value: 25 }, { id: 'd', text: { es: 'Usar solo las primeras 20 sentencias que aparezcan en la búsqueda', en: 'Use only the first 20 rulings that appear in the search', fr: 'Utiliser uniquement les 20 premières décisions apparaissant dans la recherche' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'legal-pl-prof-2', profileId: 'legal-paralegal', categoryId: 'legal-pl-professional', competencyId: 'legal-document-management', type: 'multiple-choice', content: { es: 'El sistema de archivo digital de la firma tiene documentos duplicados, carpetas inconsistentes y archivos sin nombre estandarizado. Le piden reorganizar el sistema. ¿Cómo procede?', en: 'The firm\'s digital filing system has duplicate documents, inconsistent folders, and non-standardized file names. You are asked to reorganize it. How do you proceed?', fr: 'Le système d\'archivage numérique du cabinet a des documents en double, des dossiers incohérents et des fichiers sans noms standardisés. On vous demande de le réorganiser. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Empezar a mover archivos inmediatamente según su criterio', en: 'Start moving files immediately based on your judgment', fr: 'Commencer à déplacer les fichiers immédiatement selon votre jugement' }, value: 0 }, { id: 'b', text: { es: 'Diseñar primero una estructura de nomenclatura y organización, crear un protocolo de clasificación documentado, migrar los archivos por fases validando con los abogados, y capacitar al equipo en el nuevo sistema', en: 'First design a naming and organization structure, create a documented classification protocol, migrate files in phases validating with attorneys, and train the team on the new system', fr: 'Concevoir d\'abord une structure de nomenclature et d\'organisation, créer un protocole de classification documenté, migrer les fichiers par phases en validant avec les avocats, et former l\'équipe au nouveau système' }, value: 100 }, { id: 'c', text: { es: 'Contratar un servicio externo de digitalización', en: 'Hire an external digitization service', fr: 'Engager un service externe de numérisation' }, value: 25 }, { id: 'd', text: { es: 'Crear una nueva carpeta para cada caso y dejar las antiguas intactas', en: 'Create a new folder for each case and leave old ones intact', fr: 'Créer un nouveau dossier pour chaque cas et laisser les anciens intacts' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'legal-pl-prof-3', profileId: 'legal-paralegal', categoryId: 'legal-pl-professional', competencyId: 'legal-court-procedures', type: 'multiple-choice', content: { es: 'Descubre que un escrito judicial debe presentarse mañana a primera hora, pero el abogado responsable no ha terminado las correcciones finales y estará en audiencia toda la mañana. ¿Qué hace?', en: 'You discover a court filing must be submitted tomorrow morning, but the responsible attorney has not finished final corrections and will be in hearings all morning. What do you do?', fr: 'Vous découvrez qu\'un dépôt judiciaire doit être soumis demain matin, mais l\'avocat responsable n\'a pas terminé les corrections finales et sera en audience toute la matinée. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Esperar a que el abogado termine su audiencia', en: 'Wait for the attorney to finish their hearing', fr: 'Attendre que l\'avocat finisse son audience' }, value: 0 }, { id: 'b', text: { es: 'Alertar inmediatamente al abogado sobre el plazo crítico, preparar el escrito con las correcciones pendientes marcadas, coordinar con otro abogado del equipo para la revisión final si es necesario, y asegurar que todo el material esté listo para presentación inmediata', en: 'Immediately alert the attorney about the critical deadline, prepare the brief with pending corrections marked, coordinate with another team attorney for final review if needed, and ensure all material is ready for immediate filing', fr: 'Alerter immédiatement l\'avocat sur le délai critique, préparer le mémoire avec les corrections en attente marquées, coordonner avec un autre avocat de l\'équipe pour la révision finale si nécessaire, et s\'assurer que tout est prêt pour le dépôt immédiat' }, value: 100 }, { id: 'c', text: { es: 'Presentar el escrito sin las correcciones finales', en: 'File the brief without the final corrections', fr: 'Déposer le mémoire sans les corrections finales' }, value: 0 }, { id: 'd', text: { es: 'Solicitar una prórroga al tribunal sin consultar al abogado', en: 'Request an extension from the court without consulting the attorney', fr: 'Demander une prorogation au tribunal sans consulter l\'avocat' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'legal-pl-prof-4', profileId: 'legal-paralegal', categoryId: 'legal-pl-professional', competencyId: 'legal-client-coordination', type: 'scale', content: { es: '¿Cómo califica su capacidad para coordinar con clientes, recopilar información necesaria y mantener un seguimiento preciso del estado de cada caso?', en: 'How do you rate your ability to coordinate with clients, gather necessary information, and maintain accurate tracking of each case status?', fr: 'Comment évaluez-vous votre capacité à coordonner avec les clients, recueillir les informations nécessaires et maintenir un suivi précis de l\'état de chaque dossier ?' }, scaleMin: 1, scaleMax: 5, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'legal-pl-prof-5', profileId: 'legal-paralegal', categoryId: 'legal-pl-professional', competencyId: 'legal-research-preparation', type: 'scenario', content: { es: 'Un abogado senior le asigna la preparación de un caso complejo de derecho laboral colectivo. Debe revisar 3 años de comunicaciones internas del cliente (más de 5,000 correos electrónicos), identificar documentos clave, preparar una cronología detallada de eventos y organizar la evidencia para la audiencia de pruebas que será en 10 días.\n\nDescriba su plan de trabajo detallado para completar esta tarea en el plazo dado.', en: 'A senior attorney assigns you preparation of a complex collective labor law case. You must review 3 years of the client\'s internal communications (over 5,000 emails), identify key documents, prepare a detailed timeline of events, and organize evidence for the evidentiary hearing in 10 days.\n\nDescribe your detailed work plan to complete this task within the deadline.', fr: 'Un avocat senior vous assigne la préparation d\'un dossier complexe de droit du travail collectif. Vous devez examiner 3 ans de communications internes du client (plus de 5 000 courriels), identifier les documents clés, préparer une chronologie détaillée et organiser les preuves pour l\'audience dans 10 jours.\n\nDécrivez votre plan de travail détaillé pour compléter cette tâche dans le délai imparti.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'legal-pl-prof-6', profileId: 'legal-paralegal', categoryId: 'legal-pl-professional', competencyId: 'legal-document-management', type: 'open-text', content: { es: 'Describa las mejores prácticas que sigue para organizar y mantener archivos legales, tanto físicos como digitales. ¿Cómo asegura la integridad y accesibilidad de la documentación?', en: 'Describe the best practices you follow for organizing and maintaining legal files, both physical and digital. How do you ensure documentation integrity and accessibility?', fr: 'Décrivez les meilleures pratiques que vous suivez pour organiser et maintenir les dossiers juridiques, physiques et numériques. Comment assurez-vous l\'intégrité et l\'accessibilité de la documentation ?' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const legalPlSoftSkillsQuestions: Question[] = [
  { id: 'legal-pl-ss-1', profileId: 'legal-paralegal', categoryId: 'legal-pl-soft-skills', competencyId: 'legal-attention-detail', type: 'multiple-choice', content: { es: 'Al revisar un contrato de 80 páginas antes de su firma, nota que las cifras del anexo financiero no coinciden con las mencionadas en las cláusulas principales. La diferencia es de USD 50,000. El abogado ya aprobó el documento. ¿Qué hace?', en: 'While reviewing an 80-page contract before signing, you notice the financial annex figures do not match those in the main clauses. The difference is USD 50,000. The attorney has already approved the document. What do you do?', fr: 'En révisant un contrat de 80 pages avant signature, vous remarquez que les chiffres de l\'annexe financière ne correspondent pas à ceux des clauses principales. La différence est de 50 000 USD. L\'avocat a déjà approuvé le document. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Asumir que el abogado ya verificó las cifras y no intervenir', en: 'Assume the attorney already verified the figures and not intervene', fr: 'Supposer que l\'avocat a déjà vérifié les chiffres et ne pas intervenir' }, value: 0 }, { id: 'b', text: { es: 'Documentar la discrepancia con referencias específicas a las páginas y cláusulas afectadas, informar al abogado inmediatamente con un resumen claro del problema, y sugerir las correcciones necesarias', en: 'Document the discrepancy with specific references to affected pages and clauses, immediately inform the attorney with a clear summary of the issue, and suggest necessary corrections', fr: 'Documenter l\'écart avec des références spécifiques aux pages et clauses concernées, informer immédiatement l\'avocat avec un résumé clair du problème, et suggérer les corrections nécessaires' }, value: 100 }, { id: 'c', text: { es: 'Corregir las cifras por su cuenta antes de la firma', en: 'Correct the figures yourself before signing', fr: 'Corriger les chiffres vous-même avant la signature' }, value: 0 }, { id: 'd', text: { es: 'Enviar un correo al abogado mencionando que "podría haber un error"', en: 'Send an email to the attorney mentioning there "might be an error"', fr: 'Envoyer un courriel à l\'avocat mentionnant qu\'il "pourrait y avoir une erreur"' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'legal-pl-ss-2', profileId: 'legal-paralegal', categoryId: 'legal-pl-soft-skills', competencyId: 'legal-organization-time', type: 'multiple-choice', content: { es: 'Tiene 3 tareas urgentes asignadas por diferentes abogados, todas con el mismo plazo de entrega de mañana: (1) preparar exhibiciones para un juicio, (2) compilar documentos para un cierre corporativo, y (3) investigar jurisprudencia para una moción. ¿Cómo se organiza?', en: 'You have 3 urgent tasks from different attorneys, all due tomorrow: (1) prepare exhibits for a trial, (2) compile documents for a corporate closing, and (3) research case law for a motion. How do you organize?', fr: 'Vous avez 3 tâches urgentes de différents avocats, toutes pour demain : (1) préparer des pièces pour un procès, (2) compiler des documents pour une clôture d\'entreprise, et (3) rechercher de la jurisprudence pour une motion. Comment vous organisez-vous ?' }, options: [{ id: 'a', text: { es: 'Trabajar en cada tarea en el orden en que las recibió', en: 'Work on each task in the order received', fr: 'Travailler sur chaque tâche dans l\'ordre reçu' }, value: 0 }, { id: 'b', text: { es: 'Evaluar la prioridad real de cada tarea, comunicar transparentemente a los tres abogados sobre las limitaciones de tiempo, negociar plazos o pedir ayuda si es necesario, y crear un plan de trabajo por bloques de tiempo optimizando la eficiencia', en: 'Evaluate the real priority of each task, transparently communicate to all three attorneys about time constraints, negotiate deadlines or ask for help if needed, and create a time-blocked work plan optimizing efficiency', fr: 'Évaluer la priorité réelle de chaque tâche, communiquer de manière transparente aux trois avocats sur les contraintes de temps, négocier les délais ou demander de l\'aide si nécessaire, et créer un plan de travail par blocs de temps optimisant l\'efficacité' }, value: 100 }, { id: 'c', text: { es: 'Quedarse trabajando toda la noche sin informar a nadie sobre la sobrecarga', en: 'Stay working all night without informing anyone about the overload', fr: 'Rester travailler toute la nuit sans informer personne de la surcharge' }, value: 25 }, { id: 'd', text: { es: 'Completar solo la tarea del abogado de mayor rango', en: 'Complete only the task from the highest-ranking attorney', fr: 'Ne compléter que la tâche de l\'avocat de rang le plus élevé' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'legal-pl-ss-3', profileId: 'legal-paralegal', categoryId: 'legal-pl-soft-skills', competencyId: 'legal-written-communication', type: 'multiple-choice', content: { es: 'Un abogado le pide redactar un memorando interno resumiendo un caso regulatorio complejo para que lo lea un cliente sin formación legal. ¿Cómo lo aborda?', en: 'An attorney asks you to draft an internal memo summarizing a complex regulatory case for a client without legal training. How do you approach it?', fr: 'Un avocat vous demande de rédiger un mémo interne résumant un dossier réglementaire complexe pour un client sans formation juridique. Comment l\'abordez-vous ?' }, options: [{ id: 'a', text: { es: 'Usar terminología jurídica técnica para demostrar rigor profesional', en: 'Use technical legal terminology to demonstrate professional rigor', fr: 'Utiliser une terminologie juridique technique pour démontrer la rigueur professionnelle' }, value: 0 }, { id: 'b', text: { es: 'Estructurar el memo con un resumen ejecutivo claro, puntos clave en lenguaje accesible, implicaciones prácticas para el cliente, y recomendaciones de acción, incluyendo un glosario de términos técnicos si es necesario', en: 'Structure the memo with a clear executive summary, key points in accessible language, practical implications for the client, and action recommendations, including a glossary of technical terms if needed', fr: 'Structurer le mémo avec un résumé exécutif clair, des points clés en langage accessible, des implications pratiques pour le client, et des recommandations d\'action, incluant un glossaire de termes techniques si nécessaire' }, value: 100 }, { id: 'c', text: { es: 'Copiar y pegar secciones relevantes de la regulación', en: 'Copy and paste relevant sections of the regulation', fr: 'Copier et coller les sections pertinentes de la réglementation' }, value: 0 }, { id: 'd', text: { es: 'Escribir un resumen breve de un párrafo', en: 'Write a brief one-paragraph summary', fr: 'Écrire un résumé bref d\'un paragraphe' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'legal-pl-ss-4', profileId: 'legal-paralegal', categoryId: 'legal-pl-soft-skills', competencyId: 'legal-attention-detail', type: 'scale', content: { es: '¿Cómo califica su nivel de atención al detalle al revisar documentos legales complejos?', en: 'How do you rate your level of attention to detail when reviewing complex legal documents?', fr: 'Comment évaluez-vous votre niveau d\'attention aux détails lors de la révision de documents juridiques complexes ?' }, scaleMin: 1, scaleMax: 5, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'legal-pl-ss-5', profileId: 'legal-paralegal', categoryId: 'legal-pl-soft-skills', competencyId: 'legal-organization-time', type: 'scenario', content: { es: 'Está a cargo del soporte para 4 abogados diferentes que trabajan en 12 casos activos. Cada abogado tiene su propio estilo de trabajo y expectativas. Uno de ellos frecuentemente le asigna tareas urgentes al final del día que requieren horas extras no planificadas, lo cual está afectando su vida personal y rendimiento.\n\nDescriba cómo organizaría su trabajo para ser más eficiente y cómo manejaría la situación con el abogado que asigna tareas de última hora.', en: 'You support 4 different attorneys working on 12 active cases. Each attorney has their own work style and expectations. One frequently assigns urgent tasks at end of day requiring unplanned overtime, affecting your personal life and performance.\n\nDescribe how you would organize your work more efficiently and handle the situation with the attorney assigning last-minute tasks.', fr: 'Vous soutenez 4 avocats différents travaillant sur 12 dossiers actifs. Chaque avocat a son propre style et ses attentes. L\'un d\'eux vous assigne fréquemment des tâches urgentes en fin de journée nécessitant des heures supplémentaires non planifiées, affectant votre vie personnelle et votre rendement.\n\nDécrivez comment vous organiseriez votre travail et géreriez la situation.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'legal-pl-ss-6', profileId: 'legal-paralegal', categoryId: 'legal-pl-soft-skills', competencyId: 'legal-written-communication', type: 'open-text', content: { es: 'Describa su proceso para redactar correspondencia legal profesional. ¿Cómo adapta su estilo de escritura según el destinatario (tribunal, cliente, contraparte)?', en: 'Describe your process for drafting professional legal correspondence. How do you adapt your writing style depending on the recipient (court, client, counterpart)?', fr: 'Décrivez votre processus de rédaction de correspondance juridique professionnelle. Comment adaptez-vous votre style d\'écriture selon le destinataire (tribunal, client, partie adverse) ?' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const legalPlReadinessQuestions: Question[] = [
  { id: 'legal-pl-rd-1', profileId: 'legal-paralegal', categoryId: 'legal-pl-readiness', competencyId: 'legal-tech-tools', type: 'multiple-choice', content: { es: 'La firma implementa un nuevo software de gestión de casos que cambia completamente los flujos de trabajo habituales. Muchos colegas se resisten al cambio. ¿Cuál es su actitud?', en: 'The firm implements new case management software that completely changes usual workflows. Many colleagues resist the change. What is your attitude?', fr: 'Le cabinet implémente un nouveau logiciel de gestion de dossiers qui change complètement les flux de travail habituels. Beaucoup de collègues résistent au changement. Quelle est votre attitude ?' }, options: [{ id: 'a', text: { es: 'Esperar a que otros aprendan primero y luego seguir su ejemplo', en: 'Wait for others to learn first and then follow their lead', fr: 'Attendre que d\'autres apprennent d\'abord et suivre leur exemple' }, value: 0 }, { id: 'b', text: { es: 'Aprender proactivamente el sistema, explorar todas sus funcionalidades, ofrecer ayuda a colegas que tengan dificultades, y proponer mejoras basadas en su experiencia de uso', en: 'Proactively learn the system, explore all its features, offer help to colleagues having difficulties, and propose improvements based on your usage experience', fr: 'Apprendre proactivement le système, explorer toutes ses fonctionnalités, offrir de l\'aide aux collègues en difficulté, et proposer des améliorations basées sur votre expérience d\'utilisation' }, value: 100 }, { id: 'c', text: { es: 'Seguir usando los métodos anteriores cuando sea posible', en: 'Continue using previous methods when possible', fr: 'Continuer à utiliser les méthodes précédentes quand c\'est possible' }, value: 0 }, { id: 'd', text: { es: 'Aprender solo las funciones básicas que necesita', en: 'Learn only the basic functions you need', fr: 'Apprendre uniquement les fonctions de base nécessaires' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'legal-pl-rd-2', profileId: 'legal-paralegal', categoryId: 'legal-pl-readiness', competencyId: 'legal-e-discovery', type: 'multiple-choice', content: { es: 'Un caso de litigio requiere revisar 50,000 documentos electrónicos para identificar aquellos relevantes y privilegiados. El plazo es de 3 semanas. ¿Cómo aborda el proceso de e-discovery?', en: 'A litigation case requires reviewing 50,000 electronic documents to identify relevant and privileged ones. The deadline is 3 weeks. How do you approach the e-discovery process?', fr: 'Un dossier de contentieux nécessite la révision de 50 000 documents électroniques pour identifier ceux pertinents et privilégiés. Le délai est de 3 semaines. Comment abordez-vous le processus d\'e-discovery ?' }, options: [{ id: 'a', text: { es: 'Revisar cada documento manualmente uno por uno', en: 'Review each document manually one by one', fr: 'Réviser chaque document manuellement un par un' }, value: 0 }, { id: 'b', text: { es: 'Utilizar herramientas de e-discovery con búsquedas por palabras clave, filtros por fecha y remitente, technology-assisted review (TAR) para clasificación predictiva, y un protocolo de revisión por niveles de prioridad', en: 'Use e-discovery tools with keyword searches, date and sender filters, technology-assisted review (TAR) for predictive coding, and a tiered priority review protocol', fr: 'Utiliser des outils d\'e-discovery avec des recherches par mots-clés, des filtres par date et expéditeur, la révision assistée par technologie (TAR) pour le codage prédictif, et un protocole de révision par niveaux de priorité' }, value: 100 }, { id: 'c', text: { es: 'Contratar un equipo temporal de revisión documental', en: 'Hire a temporary document review team', fr: 'Engager une équipe temporaire de révision documentaire' }, value: 25 }, { id: 'd', text: { es: 'Solicitar una extensión del plazo al tribunal', en: 'Request a deadline extension from the court', fr: 'Demander une extension de délai au tribunal' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'legal-pl-rd-3', profileId: 'legal-paralegal', categoryId: 'legal-pl-readiness', competencyId: 'legal-evolving-responsibilities', type: 'multiple-choice', content: { es: 'La firma le ofrece la oportunidad de especializarse en un área nueva de práctica (ciberseguridad legal) que requiere capacitación intensiva de 3 meses. Su carga de trabajo actual es alta. ¿Cómo responde?', en: 'The firm offers you the opportunity to specialize in a new practice area (legal cybersecurity) requiring 3 months of intensive training. Your current workload is high. How do you respond?', fr: 'Le cabinet vous offre l\'opportunité de vous spécialiser dans un nouveau domaine (cybersécurité juridique) nécessitant 3 mois de formation intensive. Votre charge actuelle est élevée. Comment répondez-vous ?' }, options: [{ id: 'a', text: { es: 'Declinar la oportunidad por la carga de trabajo actual', en: 'Decline the opportunity due to current workload', fr: 'Décliner l\'opportunité en raison de la charge de travail actuelle' }, value: 0 }, { id: 'b', text: { es: 'Aceptar con entusiasmo, proponer un plan de transición para sus responsabilidades actuales, negociar un horario que permita combinar capacitación y trabajo, y establecer metas claras de aprendizaje', en: 'Accept enthusiastically, propose a transition plan for current responsibilities, negotiate a schedule combining training and work, and set clear learning goals', fr: 'Accepter avec enthousiasme, proposer un plan de transition pour les responsabilités actuelles, négocier un horaire combinant formation et travail, et établir des objectifs d\'apprentissage clairs' }, value: 100 }, { id: 'c', text: { es: 'Aceptar pero continuar con toda su carga actual sin ajustes', en: 'Accept but continue with all current workload without adjustments', fr: 'Accepter mais continuer avec toute la charge actuelle sans ajustement' }, value: 25 }, { id: 'd', text: { es: 'Pedir que le garanticen un aumento salarial antes de aceptar', en: 'Ask for a guaranteed salary increase before accepting', fr: 'Demander une garantie d\'augmentation de salaire avant d\'accepter' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'legal-pl-rd-4', profileId: 'legal-paralegal', categoryId: 'legal-pl-readiness', competencyId: 'legal-tech-tools', type: 'scale', content: { es: '¿Qué tan cómodo se siente aprendiendo y utilizando nuevas herramientas de tecnología legal (software de gestión de casos, bases de datos legales, herramientas de productividad)?', en: 'How comfortable do you feel learning and using new legal technology tools (case management software, legal databases, productivity tools)?', fr: 'À quel point vous sentez-vous à l\'aise pour apprendre et utiliser de nouveaux outils de technologie juridique (logiciels de gestion, bases de données juridiques, outils de productivité) ?' }, scaleMin: 1, scaleMax: 5, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'legal-pl-rd-5', profileId: 'legal-paralegal', categoryId: 'legal-pl-readiness', competencyId: 'legal-e-discovery', type: 'scenario', content: { es: 'La firma acaba de implementar una herramienta de IA que puede clasificar automáticamente documentos legales, extraer cláusulas clave de contratos, y generar borradores de correspondencia. El abogado senior le pide que lidere la prueba piloto de la herramienta en su equipo.\n\nDescriba cómo planificaría y ejecutaría esta prueba piloto, incluyendo cómo evaluaría la precisión y utilidad de la herramienta.', en: 'The firm just implemented an AI tool that can automatically classify legal documents, extract key contract clauses, and generate correspondence drafts. The senior attorney asks you to lead the tool\'s pilot test in your team.\n\nDescribe how you would plan and execute this pilot, including how you would evaluate the tool\'s accuracy and usefulness.', fr: 'Le cabinet vient d\'implémenter un outil d\'IA capable de classifier automatiquement les documents juridiques, extraire les clauses clés des contrats, et générer des projets de correspondance. L\'avocat senior vous demande de diriger le test pilote dans votre équipe.\n\nDécrivez comment vous planifieriez et exécuteriez ce pilote, incluant l\'évaluation de la précision et de l\'utilité de l\'outil.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'legal-pl-rd-6', profileId: 'legal-paralegal', categoryId: 'legal-pl-readiness', competencyId: 'legal-evolving-responsibilities', type: 'open-text', content: { es: 'Describa cómo se mantiene actualizado con los cambios en la tecnología legal y las nuevas herramientas disponibles. ¿Qué habilidades cree que serán más importantes para los paralegales en los próximos 5 años?', en: 'Describe how you stay current with changes in legal technology and new available tools. What skills do you believe will be most important for paralegals in the next 5 years?', fr: 'Décrivez comment vous restez à jour avec les changements en technologie juridique et les nouveaux outils disponibles. Quelles compétences pensez-vous seront les plus importantes pour les parajuristes dans les 5 prochaines années ?' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

